import React, { useEffect, useState } from 'react';
import { Button, Modal, Select } from '@linm-soft/common-components';
import type { ErpListHeightMode, ErpListTableConfig } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';

export interface VoucherListTableConfigModalProps {
  isOpen: boolean;
  onClose: () => void;
  testIdPrefix: string;
  config: ErpListTableConfig;
  onSave: (config: ErpListTableConfig) => void;
}

export const VoucherListTableConfigModal: React.FC<VoucherListTableConfigModalProps> = ({
  isOpen,
  onClose,
  testIdPrefix,
  config,
  onSave,
}) => {
  const [draft, setDraft] = useState(config);

  useEffect(() => {
    if (isOpen) setDraft(config);
  }, [isOpen, config]);

  const handleSave = () => {
    onSave(draft);
    onClose();
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Sửa config — bảng danh sách"
      data-testid={`${testIdPrefix}-list-config-modal`}
    >
      <div className={styles.modalBody}>
        <label className={styles.label}>
          <input
            type="checkbox"
            checked={draft.stickyHeader}
            onChange={e => setDraft(d => ({ ...d, stickyHeader: e.target.checked }))}
            data-testid={`${testIdPrefix}-list-config-sticky`}
          />
          {' '}Giữ header khi scroll
        </label>
        <label className={styles.label}>
          <input
            type="checkbox"
            checked={draft.resizable}
            onChange={e => setDraft(d => ({ ...d, resizable: e.target.checked }))}
            data-testid={`${testIdPrefix}-list-config-resizable`}
          />
          {' '}Cho phép kéo độ rộng cột (cần columnDefs schema)
        </label>
        <div className={styles.field}>
          <span className={styles.label}>Chiều cao bảng</span>
          <Select
            value={draft.heightMode}
            onChange={e => setDraft(d => ({
              ...d,
              heightMode: e.target.value as ErpListHeightMode,
            }))}
            options={[
              { value: 'auto', label: 'Tự động' },
              { value: 'fixed', label: 'Cố định' },
            ]}
            data-testid={`${testIdPrefix}-list-config-height-mode`}
          />
        </div>
        {draft.heightMode === 'fixed' && (
          <div className={styles.field}>
            <span className={styles.label}>Height (CSS)</span>
            <input
              className={styles.readonlyInput}
              value={draft.height ?? '420px'}
              onChange={e => setDraft(d => ({ ...d, height: e.target.value || '420px' }))}
              placeholder="420px"
              data-testid={`${testIdPrefix}-list-config-height`}
            />
          </div>
        )}
      </div>
      <div className={styles.modalActions}>
        <Button variant="secondary" onClick={onClose}>Hủy</Button>
        <Button variant="primary" onClick={handleSave} data-testid={`${testIdPrefix}-list-config-save`}>
          Lưu
        </Button>
      </div>
    </Modal>
  );
};
